def slog(*args):
    """Append a timestamped line to ~/.amux/logs/server.log (and stderr if TTY)."""
    import datetime
    msg = " ".join(str(a) for a in args)
    line = f"{datetime.datetime.now().strftime('%Y-%m-%d %H:%M:%S')} {msg}\n"
    # Only write to stderr if it's a real terminal — launchd redirects stderr
    # to server.log, so writing to both would double every line.
    if sys.stderr.isatty():
        sys.stderr.write(line)
    try:
        with _server_log_lock:
            with open(SERVER_LOG, "a") as f:
                f.write(line)
    except Exception:
        pass

# ── Browser automation helpers ────────────────────────────────────────────────
_BROWSER_HELPER = Path.home() / ".amux" / "browser-helper.js"
_NODE_BIN = shutil.which("node") or "/usr/local/bin/node"

def _pw_list_profiles() -> list:
    d = Path.home() / ".amux" / "playwright-auth" / "profiles"
    if not d.exists():
        return []
    return sorted(p.name for p in d.iterdir() if p.is_dir())

def _browser_call(cmd: dict, timeout_s: int = 40) -> dict:
    """Run ~/.amux/browser-helper.js with a JSON command, return parsed result."""
    try:
        r = subprocess.run(
            [_NODE_BIN, str(_BROWSER_HELPER)],
            input=json.dumps(cmd),
            capture_output=True,
            text=True,
            timeout=timeout_s,
        )
        out = r.stdout.strip()
        if not out:
            return {"error": r.stderr.strip() or f"node exited {r.returncode}"}
        return json.loads(out)
    except subprocess.TimeoutExpired:
        return {"error": "browser operation timed out"}
    except Exception as e:
        return {"error": str(e)}

