def get_db() -> sqlite3.Connection:
    """Return a per-thread SQLite connection with WAL mode enabled."""
    if not hasattr(_db_local, "conn"):
        conn = sqlite3.connect(str(_DB_PATH), check_same_thread=False)
        conn.row_factory = sqlite3.Row
        conn.execute("PRAGMA journal_mode=WAL")
        conn.execute("PRAGMA synchronous=NORMAL")
        conn.execute("PRAGMA foreign_keys=ON")
        conn.execute("PRAGMA busy_timeout=5000")
        _db_local.conn = conn
    return _db_local.conn


def _init_claude_config():
    """Pre-configure ~/.claude.json to skip the interactive setup wizard.

    When ANTHROPIC_API_KEY is available in the environment, this writes the
    minimal config needed so claude starts directly in interactive mode without
    showing the onboarding wizard, folder trust dialog, or API key prompt.
    """
    import json as _json
    import pathlib as _pathlib

    api_key = os.environ.get("ANTHROPIC_API_KEY", "")
    if not api_key:
        return

    # claude uses the last 20 chars of the key as its identifier
    key_hash = api_key[-20:]

    claude_json = _pathlib.Path.home() / ".claude.json"
    cfg = {}
    if claude_json.exists():
        try:
            cfg = _json.loads(claude_json.read_text())
        except Exception:
            cfg = {}

    changed = False

    # Skip the onboarding wizard (theme + auth steps)
    if not cfg.get("hasCompletedOnboarding"):
        cfg["hasCompletedOnboarding"] = True
        cfg.setdefault("theme", "dark")
        changed = True

    # Approve API key so the "use this key?" prompt is skipped
    responses = cfg.setdefault("customApiKeyResponses", {"approved": [], "rejected": []})
    approved = responses.get("approved", [])
    rejected = responses.get("rejected", [])
    if key_hash not in approved:
        responses["approved"] = [key_hash] + [k for k in approved if k != key_hash]
        responses["rejected"] = [k for k in rejected if k != key_hash]
        changed = True

    # Trust common workspaces to skip the "do you trust this folder?" dialog.
    # Pre-trust the home directory (default session work_dir) and /app (cloud image work_dir).
    import pathlib as _pathlib2
    trust_dirs = [str(_pathlib2.Path.home()), "/app"]
    projects = cfg.setdefault("projects", {})
    for trust_dir in trust_dirs:
        proj = projects.setdefault(trust_dir, {})
        if not proj.get("hasTrustDialogAccepted"):
            proj["hasTrustDialogAccepted"] = True
            changed = True

    if changed:
        claude_json.write_text(_json.dumps(cfg, indent=2))

    # ── ~/.claude/settings.json — yolo mode + auto-accept ────────────────────
    # skipDangerousModePermissionPrompt: skip the "enter dangerous mode?" prompt
    # when --dangerously-skip-permissions is passed (yolo mode).
    # Permissions allow list matches what --dangerously-skip-permissions grants.
    settings_file = _pathlib.Path.home() / ".claude" / "settings.json"
    settings_file.parent.mkdir(parents=True, exist_ok=True)
    try:
        settings = _json.loads(settings_file.read_text()) if settings_file.exists() else {}
    except Exception:
        settings = {}
    settings_changed = False
    if not settings.get("skipDangerousModePermissionPrompt"):
        settings["skipDangerousModePermissionPrompt"] = True
        settings_changed = True
    # Allow all tools so sessions never get blocked on permission prompts.
    # --dangerously-skip-permissions is rejected as root (Claude v2.1.69+),
    # so we grant permissions via settings.json instead.
    perms = settings.setdefault("permissions", {})
    allow = perms.setdefault("allow", [])
    for tool in ["Bash(*)", "Edit(*)", "Write(*)", "MultiEdit(*)", "NotebookEdit(*)"]:
        if tool not in allow:
            allow.append(tool)
            settings_changed = True
    if settings_changed:
        settings_file.write_text(_json.dumps(settings, indent=2))


def _auto_trust_dir(work_dir: str):
    """Pre-trust a directory in ~/.claude.json so Claude doesn't show the folder trust dialog."""
    import json as _json
    import pathlib as _pathlib
    claude_json = _pathlib.Path.home() / ".claude.json"
    try:
        cfg = _json.loads(claude_json.read_text()) if claude_json.exists() else {}
    except Exception:
        cfg = {}
    projects = cfg.setdefault("projects", {})
    proj = projects.setdefault(work_dir, {})
    if not proj.get("hasTrustDialogAccepted"):
        proj["hasTrustDialogAccepted"] = True
        proj["hasCompletedProjectOnboarding"] = True
        claude_json.write_text(_json.dumps(cfg, indent=2))


    # ── ~/.claude/commands/ — skills as slash commands ────────────────────────
    # Sync all skills from SQLite into ~/.claude/commands/ so they're available
    # as /skill-name slash commands in every Claude session.
    try:
        commands_dir = _pathlib.Path.home() / ".claude" / "commands"
        commands_dir.mkdir(parents=True, exist_ok=True)
        db = get_db()
        rows = db.execute("SELECT name, content FROM skills").fetchall()
        for row in rows:
            try:
                (commands_dir / (row["name"] + ".md")).write_text(row["content"])
            except Exception:
                pass
    except Exception:
        pass

    # ── /usr/local/bin/amux — CLI stub for sessions ───────────────────────────
    # Writes a minimal amux shim so Claude sessions can use `amux board ...`
    # commands without needing the full amux bash script installed.
    _amux_stub = r"""#!/bin/sh
# amux CLI stub — proxies board/session commands to the amux server API
AMUX_URL="${AMUX_URL:-https://localhost:8822}"
cmd="$1"; shift 2>/dev/null || true

case "$cmd" in
  board)
    sub="$1"; shift 2>/dev/null || true
    case "$sub" in
      done|doing|todo|backlog|discarded)
        for id in "$@"; do
          curl -sk -X PATCH -H 'Content-Type: application/json' \
            -d "{\"status\":\"$sub\"}" "$AMUX_URL/api/board/$id" >/dev/null
        done ;;
      add)
        title="$*"
        curl -sk -X POST -H 'Content-Type: application/json' \
          -d "{\"title\":\"$title\",\"status\":\"todo\",\"session\":\"${AMUX_SESSION:-}\"}" "$AMUX_URL/api/board" ;;
      list|ls|"")
        curl -sk "$AMUX_URL/api/board" | python3 -c "
import json,sys
items=json.load(sys.stdin)
for i in items: print(i.get('id',''),i.get('status',''),i.get('title',''))" ;;
      *) echo "amux board: unknown subcommand: $sub" >&2; exit 1 ;;
    esac ;;
  crm)
    sub="$1"; shift 2>/dev/null || true
    case "$sub" in
      add)
        # Usage: amux crm add "Name" [company=X] [email=Y] [role=Z] [phone=P] [linkedin=L]
        json=$(python3 -c "
import sys,json
args=sys.argv[1:]; fields={}; name_parts=[]
for a in args:
    if '=' in a: k,v=a.split('=',1); fields[k]=v
    else: name_parts.append(a)
if name_parts: fields['name']=' '.join(name_parts)
print(json.dumps(fields))" "$@")
        curl -sk -X POST -H 'Content-Type: application/json' -d "$json" "$AMUX_URL/api/crm/contacts" | python3 -c "
import json,sys; d=json.load(sys.stdin)
print(d.get('id','error'),'-',d.get('error','created'))" ;;
      update)
        # Usage: amux crm update PPL-1 company=X email=Y role=Z ...
        cid="$1"; shift 2>/dev/null || true
        json=$(python3 -c "
import sys,json; fields={}
for a in sys.argv[1:]:
    if '=' in a: k,v=a.split('=',1); fields[k]=v
print(json.dumps(fields))" "$@")
        curl -sk -X PATCH -H 'Content-Type: application/json' -d "$json" "$AMUX_URL/api/crm/contacts/$cid" | python3 -c "
import json,sys; d=json.load(sys.stdin)
print('updated' if d.get('ok') else d.get('error','failed'))" ;;
      get)
        cid="$1"
        curl -sk "$AMUX_URL/api/crm/contacts/$cid" | python3 -c "
import json,sys
c=json.load(sys.stdin)
if 'error' in c: print('Error:',c['error']); sys.exit(1)
print(c.get('id'),c.get('name'))
for f in ('company','role','email','phone','linkedin','twitter'):
    v=c.get(f,'')
    if v: print('  '+f+':',v)
tags=c.get('tags',[])
if tags: print('  tags:',', '.join(tags))
ixs=c.get('interactions',[])
if ixs: print('  last interaction:',ixs[0].get('date'),'-',ixs[0].get('notes','')[:60])" ;;
      log)
        cid="$1"; shift 2>/dev/null || true; notes="$*"
        curl -sk -X POST -H 'Content-Type: application/json' \
          -d "{\"notes\":\"$notes\",\"date\":\"$(date +%Y-%m-%d)\",\"type\":\"other\"}" \
          "$AMUX_URL/api/crm/contacts/$cid/interactions" ;;
      followups|fu)
        curl -sk "$AMUX_URL/api/crm/followups" | python3 -c "
import json,sys
items=json.load(sys.stdin)
if not items: print('No pending follow-ups')
for i in items: print(i.get('follow_up_date',''),i.get('name',''),'-',i.get('follow_up_note',''))" ;;
      list|ls|"")
        curl -sk "$AMUX_URL/api/crm/contacts" | python3 -c "
import json,sys
cs=json.load(sys.stdin)
if not cs: print('No contacts yet')
for c in cs: print(c.get('id',''),c.get('name',''),c.get('company',''))" ;;
      *) echo "amux crm: unknown subcommand: $sub" >&2; exit 1 ;;
    esac ;;
  session|sessions)
    curl -sk "$AMUX_URL/api/sessions" | python3 -c "
import json,sys
for s in json.load(sys.stdin): print(s['name'], '(running)' if s.get('running') else '')" ;;
  share)
    session="$1"; shift 2>/dev/null || true
    perms="${1:-output}"
    result=$(curl -sk -X POST -H 'Content-Type: application/json' \
      -d "{\"perms\":\"$perms\"}" "$AMUX_URL/api/sessions/$session/share")
    echo "$result" | python3 -c "import json,sys; d=json.load(sys.stdin); print(d.get('url','error: '+d.get('error','unknown')))" ;;
  unshare)
    session="$1"; shift 2>/dev/null || true
    token="$1"
    curl -sk -X DELETE -H 'Content-Type: application/json' \
      -d "{\"token\":\"$token\"}" "$AMUX_URL/api/sessions/$session/share" >/dev/null
    echo "revoked" ;;
  help|--help|-h|"")
    echo "amux board <done|doing|todo> <ITEM_ID>  — update board item status"
    echo "amux board add <title>                  — create a new board item"
    echo "amux board list                         — list board items"
    echo "amux crm add <name> [field=val ...]    — add a contact (fields: company email role phone linkedin)"
    echo "amux crm update <PPL-id> [field=val ..]  — update contact fields"
    echo "amux crm get <PPL-id>                   — show contact details"
    echo "amux crm log <PPL-id> <notes>           — log an interaction"
    echo "amux crm followups                      — show upcoming follow-ups"
    echo "amux crm list                           — list all contacts"
    echo "amux sessions                           — list sessions"
    echo "amux share <session> [perms]            — create a public share link (perms: output, output+files, output+files+notes)"
    echo "amux unshare <session> [token]          — revoke share link(s)" ;;
  *) echo "amux: unknown command: $cmd" >&2; exit 1 ;;
esac
"""
    stub_path = _pathlib.Path("/usr/local/bin/amux")
    try:
        if not stub_path.exists() or stub_path.read_text() != _amux_stub:
            stub_path.write_text(_amux_stub)
            stub_path.chmod(0o755)
    except Exception:
        pass  # may not have write permission on local dev machines


